mapper.delete:
DELETE FROM energy_summaries
WHERE summary_type = #{summaryType}
  AND summary_at >= #{from}
  AND summary_at < #{to}

mapper.select:
SELECT id, plant_id, facility_id, measured_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, created_at
FROM energy_measurements

    AND plant_id = #{plantId}
    AND facility_id = #{facilityId}
    AND measured_at >= #{from}
    AND measured_at <= #{to}

ORDER BY measured_at DESC, id DESC
LIMIT #{limit}

SELECT id, plant_id, facility_id, summary_type, summary_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, carbon_emission
FROM energy_summaries

    AND plant_id = #{plantId}


            AND facility_id = #{facilityId}


            AND facility_id IS NULL


    AND summary_type = #{summaryType}
    AND summary_at >= #{from}
    AND summary_at <= #{to}

ORDER BY summary_at ASC, id ASC

WITH ordered_measurements AS ( SELECT id, plant_id, facility_id, measured_at, DATE(measured_at) AS measured_date, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, LAG(electricity_kwh) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_electricity_kwh, LAG(gas_m3) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_gas_m3, LAG(water_ton) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_water_ton, LAG(solar_kwh) OVER ( PARTITION BY plant_id, facility_id, DATE(measured_at) ORDER BY measured_at ASC, id ASC ) AS previous_solar_kwh FROM energy_measurements
AND plant_id = #{plantId} AND facility_id = #{facilityId} AND measured_at >= #{from} AND measured_at <= #{to}
) SELECT NULL AS id, plant_id, facility_id, 'DAILY' AS summary_type, CAST(measured_date AS DATETIME) AS summary_at, COALESCE(SUM( CASE WHEN previous_electricity_kwh IS NULL THEN 0 WHEN electricity_kwh >= previous_electricity_kwh THEN electricity_kwh - previous_electricity_kwh ELSE 0 END ), 0) AS electricity_kwh, COALESCE(SUM( CASE WHEN previous_gas_m3 IS NULL THEN 0 WHEN gas_m3 >= previous_gas_m3 THEN gas_m3 - previous_gas_m3 ELSE 0 END ), 0) AS gas_m3, COALESCE(SUM( CASE WHEN previous_water_ton IS NULL THEN 0 WHEN water_ton >= previous_water_ton THEN water_ton - previous_water_ton ELSE 0 END ), 0) AS water_ton, COALESCE(SUM( CASE WHEN previous_solar_kwh IS NULL THEN 0 WHEN solar_kwh >= previous_solar_kwh THEN solar_kwh - previous_solar_kwh ELSE 0 END ), 0) AS solar_kwh, COALESCE(MAX(peak_kw), 0) AS peak_kw, NULL AS carbon_emission FROM ordered_measurements GROUP BY plant_id, facility_id, measured_date ORDER BY summary_at ASC

SELECT DATE(es.summary_at)
FROM energy_summaries es
JOIN facilities f ON f.id = es.facility_id
WHERE es.plant_id = #{plantId}
  AND f.plant_id = #{plantId}
  AND f.facility_type = #{facilityType}
  AND f.id >= 10000
  AND MOD(f.id, 10000) BETWEEN 1 AND 24
  AND es.summary_type = 'DAILY'
  AND DATE(es.summary_at) = #{targetDate}
LIMIT 1

SELECT DATE(em.measured_at)
FROM energy_measurements em
JOIN facilities f ON f.id = em.facility_id
WHERE em.plant_id = #{plantId}
  AND f.plant_id = #{plantId}
  AND f.facility_type = #{facilityType}
  AND f.id >= 10000
  AND MOD(f.id, 10000) BETWEEN 1 AND 24
ORDER BY em.measured_at DESC, em.id DESC
LIMIT 1

WITH target_summary AS ( SELECT facility_id,
gas_m3 water_ton solar_kwh electricity_kwh AS usage_amount, summary_at FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'DAILY' AND facility_id IS NOT NULL AND DATE(summary_at) = #{usageDate} ), target_measurement_usage AS ( SELECT facility_id, SUM(
gas_m3 water_ton solar_kwh electricity_kwh
) AS usage_amount, MAX(summary_at) AS summary_at FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'HOURLY' AND facility_id IS NOT NULL AND summary_at >= #{usageFrom} AND summary_at < #{usageTo} GROUP BY facility_id ), yesterday_summary AS ( SELECT facility_id,
gas_m3 water_ton solar_kwh electricity_kwh AS usage_amount FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'DAILY' AND facility_id IS NOT NULL AND DATE(summary_at) = #{yesterdayDate} ), yesterday_measurement_usage AS ( SELECT facility_id, SUM(
gas_m3 water_ton solar_kwh electricity_kwh
) AS usage_amount FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'HOURLY' AND facility_id IS NOT NULL AND summary_at >= TIMESTAMP(#{yesterdayDate}) AND summary_at < TIMESTAMP(#{usageDate}) GROUP BY facility_id ), monthly_average AS ( SELECT facility_id, AVG(COALESCE(
gas_m3 water_ton solar_kwh electricity_kwh , 0 )) AS monthly_average_kwh FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'DAILY' AND facility_id IS NOT NULL AND summary_at >= #{monthStart} AND summary_at < #{nextMonthStart} GROUP BY facility_id ), monthly_measurement_average AS ( SELECT facility_id, AVG(
gas_m3 water_ton solar_kwh electricity_kwh
) AS monthly_average_kwh FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'DAILY' AND facility_id IS NOT NULL AND summary_at >= #{monthStart} AND summary_at < #{nextMonthStart} GROUP BY facility_id ), latest_measurement AS ( SELECT facility_id, MAX(summary_at) AS latest_measured_at FROM energy_summaries WHERE plant_id = #{plantId} AND summary_type = 'HOURLY' AND summary_at >= #{usageFrom} AND summary_at < #{usageTo} GROUP BY facility_id ) SELECT f.id AS facility_id, f.name AS facility_name, f.facility_type, f.status AS facility_status, CAST(#{usageDate} AS DATE) AS usage_date, ROUND(COALESCE(tmu.usage_amount, ts.usage_amount, 0), 2) AS today_usage_kwh, ROUND(COALESCE(ymu.usage_amount, ys.usage_amount, 0), 2) AS yesterday_usage_kwh, ROUND(COALESCE(mma.monthly_average_kwh, ma.monthly_average_kwh, 0), 2) AS monthly_average_kwh, ROUND( CASE WHEN COALESCE(ymu.usage_amount, ys.usage_amount, 0) = 0 THEN 0 ELSE (COALESCE(tmu.usage_amount, ts.usage_amount, 0) - COALESCE(ymu.usage_amount, ys.usage_amount, 0)) / COALESCE(ymu.usage_amount, ys.usage_amount, 0) * 100 END, 1 ) AS today_vs_yesterday_rate, ROUND( CASE WHEN COALESCE(mma.monthly_average_kwh, ma.monthly_average_kwh, 0) = 0 THEN 0 ELSE (COALESCE(tmu.usage_amount, ts.usage_amount, 0) - COALESCE(mma.monthly_average_kwh, ma.monthly_average_kwh, 0)) / COALESCE(mma.monthly_average_kwh, ma.monthly_average_kwh, 0) * 100 END, 1 ) AS today_vs_monthly_average_rate, COALESCE(lm.latest_measured_at, tmu.summary_at, ts.summary_at) AS latest_measured_at FROM facilities f LEFT JOIN target_summary ts ON ts.facility_id = f.id LEFT JOIN target_measurement_usage tmu ON tmu.facility_id = f.id LEFT JOIN yesterday_summary ys ON ys.facility_id = f.id LEFT JOIN yesterday_measurement_usage ymu ON ymu.facility_id = f.id LEFT JOIN monthly_average ma ON ma.facility_id = f.id LEFT JOIN monthly_measurement_average mma ON mma.facility_id = f.id LEFT JOIN latest_measurement lm ON lm.facility_id = f.id WHERE f.plant_id = #{plantId} AND f.facility_type = #{facilityType} AND f.id >= 10000 AND MOD(f.id, 10000) BETWEEN 1 AND 24 ORDER BY f.id ASC

SELECT id, plant_id, facility_id, measured_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, created_at
FROM energy_measurements
WHERE plant_id = #{plantId}
  AND facility_id = #{facilityId}
ORDER BY measured_at DESC, id DESC
LIMIT 1

SELECT id, plant_id, facility_id, measured_at, electricity_kwh, gas_m3, water_ton, solar_kwh, peak_kw, created_at
FROM energy_measurements
WHERE plant_id = #{plantId}
  AND facility_id = #{facilityId}
  AND measured_at < #{measuredAt}
ORDER BY measured_at DESC, id DESC
LIMIT 1

SELECT
    #{from} AS measured_at,
    ROUND(COALESCE(SUM(gas_m3), 0), 2) AS gas_usage_m3,
    ROUND(COALESCE(SUM(water_ton), 0), 2) AS water_usage_ton
FROM energy_summaries
WHERE plant_id = #{plantId}
  AND summary_type = 'DAILY'
  AND facility_id IS NULL
  AND summary_at >= #{from}
  AND summary_at < #{to}
